    if (VectorizableTree.size() > 1)
      return false;
    // A single-node tree is not a reduction, unless it is a gather from
    // multiple other reductions.
    return VectorizableTree.size() == 1 &&
           VectorizableTree.back()->getNumOperands() == 0;
  }
  return VectorizableTree.size() <= 1 &&
         !VectorizableTree[0]->isOpcodeOrAlt(Instruction::Load);
